import{_ as e,o as d,c as a,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Agent 工具","description":"","frontmatter":{},"headers":[],"relativePath":"features/agent-tools.md","filePath":"features/agent-tools.md"}'),o={name:"features/agent-tools.md"};function r(i,t,n,s,c,h){return d(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="agent-工具" tabindex="-1">Agent 工具 <a class="header-anchor" href="#agent-工具" aria-label="Permalink to &quot;Agent 工具&quot;">​</a></h1><p>Lyra Code 的 Agent 工具将你的 Android 设备变成强大的 AI 工作站。所有工具操作均需要<strong>用户审核批准</strong>，确保安全可控。</p><h2 id="文件操作" tabindex="-1">文件操作 <a class="header-anchor" href="#文件操作" aria-label="Permalink to &quot;文件操作&quot;">​</a></h2><p>Agent 可以在工作区内读写和管理文件：</p><table tabindex="0"><thead><tr><th>工具</th><th>说明</th></tr></thead><tbody><tr><td><code>read_file</code></td><td>读取 1 MB 以内的文本文件</td></tr><tr><td><code>write_file</code></td><td>创建或覆盖文件，支持逐行写入</td></tr><tr><td><code>append_file</code></td><td>向已有文件追加内容</td></tr><tr><td><code>delete_file_or_folder</code></td><td>删除文件或空目录</td></tr><tr><td><code>rename_move</code></td><td>在工作区内重命名或移动文件</td></tr><tr><td><code>create_folder</code></td><td>创建新目录</td></tr><tr><td><code>search_files</code></td><td>按文件名、扩展名或路径搜索</td></tr><tr><td><code>get_file_info</code></td><td>获取文件元数据</td></tr></tbody></table><h2 id="原生下载" tabindex="-1">原生下载 <a class="header-anchor" href="#原生下载" aria-label="Permalink to &quot;原生下载&quot;">​</a></h2><p>直接从 HTTP/HTTPS 地址下载文件：</p><ul><li>保存到工作区或 Android 共享存储（如 Download 文件夹）</li><li>自定义请求头</li><li>可配置超时时间</li><li>可选的 SHA-256 完整性校验</li><li>自动跟随重定向</li></ul><div class="tip custom-block"><p class="custom-block-title">推荐方式</p><p>原生下载是获取文件的首选方式。Termux 的 <code>curl</code> / <code>wget</code> 仅作为备用方案。</p></div><h2 id="命令执行" tabindex="-1">命令执行 <a class="header-anchor" href="#命令执行" aria-label="Permalink to &quot;命令执行&quot;">​</a></h2><p>通过 Termux <code>RunCommandService</code> 执行 Shell 命令：</p><ul><li>完整的 <code>stdout</code> / <code>stderr</code> 反馈</li><li>可配置超时（最长 600 秒）</li><li>支持多行命令</li><li>返回退出码</li></ul><h2 id="ftp-sftp-文件传输" tabindex="-1">FTP / SFTP 文件传输 <a class="header-anchor" href="#ftp-sftp-文件传输" aria-label="Permalink to &quot;FTP / SFTP 文件传输&quot;">​</a></h2><p>直接管理远程 FTP/FTPS/SFTP 服务器上的文件（需提前在设置中配置服务器）：</p><table tabindex="0"><thead><tr><th>工具</th><th>说明</th></tr></thead><tbody><tr><td><code>file_transfer_list</code></td><td>列出远程目录下的文件</td></tr><tr><td><code>file_transfer_search</code></td><td>按文件名搜索远程文件</td></tr><tr><td><code>file_transfer_download_to_workspace</code></td><td>下载远程文件到工作区</td></tr><tr><td><code>file_transfer_upload_from_workspace</code></td><td>上传工作区文件到远程服务器</td></tr></tbody></table><p>支持 FTP（明文）、FTPS（隐式/显式 TLS）和 SFTP（SSH 文件传输协议）。</p><h2 id="网页工具" tabindex="-1">网页工具 <a class="header-anchor" href="#网页工具" aria-label="Permalink to &quot;网页工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>说明</th></tr></thead><tbody><tr><td><code>web_search</code></td><td>搜索互联网并获取排序结果（支持域名黑名单过滤）</td></tr><tr><td><code>read_web_page</code></td><td>读取并解析网页正文</td></tr><tr><td><code>mark_web_sources</code></td><td>标注 AI 回复中引用的来源</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">黑名单过滤</p><p>你可以在设置中添加域名黑名单，AI 联网搜索时将自动屏蔽这些网站，防止垃圾或恶意网页污染输出结果。支持 <code>*</code> 通配符匹配子域名。</p></div><h2 id="本地静态服务器" tabindex="-1">本地静态服务器 <a class="header-anchor" href="#本地静态服务器" aria-label="Permalink to &quot;本地静态服务器&quot;">​</a></h2><p>在工作区内一键启动 HTTP/HTTPS 静态服务器，用于调试 HTML/CSS/JS 网站：</p><ul><li>支持本机访问和局域网访问</li><li>可选的 Basic 认证密码保护</li><li>支持 HTTPS（自定义证书或内置自签名证书）</li><li>支持 SPA 回退路由和目录列表</li><li>可自定义监听地址和端口</li><li>mDNS 服务发现支持</li></ul><h2 id="后台任务" tabindex="-1">后台任务 <a class="header-anchor" href="#后台任务" aria-label="Permalink to &quot;后台任务&quot;">​</a></h2><p>支持创建定时或一次性后台任务，让 AI 在后台自动执行：</p><ul><li><strong>一次性</strong> — 指定时间执行一次</li><li><strong>每日</strong> — 每天固定时间执行</li><li><strong>每周</strong> — 每周某天执行</li><li><strong>每月</strong> — 每月某天执行</li><li>每个任务可独立指定模型和配置方案</li><li>任务完成后可发送桌面通知</li></ul><h2 id="规划与审查" tabindex="-1">规划与审查 <a class="header-anchor" href="#规划与审查" aria-label="Permalink to &quot;规划与审查&quot;">​</a></h2><ul><li><strong>TODO 列表</strong> — 多步骤任务规划，实时更新进度</li><li><strong>文件变更审查</strong> — 每次文件修改都有 Diff 可视化对比</li><li><strong>工具审批</strong> — 每次工具调用均可审查后批准</li><li><strong>会话内跳过确认</strong> — 在可信会话中可选择性跳过重复确认</li><li><strong>任务执行计时</strong> — 实时显示已运行时长</li></ul><h2 id="上下文感知" tabindex="-1">上下文感知 <a class="header-anchor" href="#上下文感知" aria-label="Permalink to &quot;上下文感知&quot;">​</a></h2><p>Agent 能够感知以下信息：</p><ul><li><strong>时间</strong> — 当前本地时间、时区和时间戳</li><li><strong>位置</strong> — 设备定位（需授权），用于位置相关查询</li><li><strong>设备硬件</strong> — 完整的诊断和系统信息</li></ul><h2 id="配置管理" tabindex="-1">配置管理 <a class="header-anchor" href="#配置管理" aria-label="Permalink to &quot;配置管理&quot;">​</a></h2><p>Agent 可以通过自然语言管理自身配置：</p><ul><li>添加、修改、启用或禁用 MCP 服务器</li><li>配置 SSH 连接</li><li>管理 WebDAV 存储</li><li>配置 FTP/FTPS/SFTP 文件传输服务器</li><li>导入和管理技能包（Skills）</li><li>管理后台定时任务</li><li>开关 Agent 工具</li></ul>',33)])])}const _=e(o,[["render",r]]);export{p as __pageData,_ as default};
